    rec("RLN-P1-C01-Entry1-7-2", "If $\\alpha=\\dfrac{1-\\sqrt{5}}{2}$ and $\\beta=\\dfrac{1+\\sqrt{5}}{2}$, then $\\varphi(q)+\\sqrt{5}\\,\\varphi(q^5)=(1+\\sqrt{5})f(-q^2)\\prod_{n\\text{ odd}}(1+\\alpha q^n+q^{2n})\\prod_{n\\text{ even}}(1-\\beta q^n+q^{2n})$, $\\varphi(q)-\\sqrt{5}\\,\\varphi(q^5)=(1-\\sqrt{5})f(-q^2)\\prod_{n\\text{ even}}(1-\\alpha q^n+q^{2n})\\prod_{n\\text{ odd}}(1+\\beta q^n+q^{2n})$, $\\psi(q^2)+q\\sqrt{5}\\,\\psi(q^{10})=f(-q^2)\\prod_{n\\text{ odd}}(1+\\alpha q^n+q^{2n})\\prod_{n\\text{ odd}}(1-\\beta q^n+q^{2n})$, and $\\psi(q^2)-q\\sqrt{5}\\,\\psi(q^{10})=f(-q^2)\\prod_{n\\text{ odd}}(1-\\alpha q^n+q^{2n})\\prod_{n\\text{ odd}}(1+\\beta q^n+q^{2n})$."),
